78	// ── Goal helpers ──
79	
80	export function createGoal(data: {
81	  title: string;
82	  description?: string;
83	  startValue: number;
84	  targetValue: number;
85	  currentValue?: number;
86	  unit: string;
87	  deadline?: string;
88	  linkedHabitIds?: string[];
89	}): Goal {
90	  const goal: Goal = {
91	    id: crypto.randomUUID(),
92	    userId: "demo",
93	    title: data.title,
94	    description: data.description || null,
95	    startValue: data.startValue,
96	    targetValue: data.targetValue,
97	    currentValue: data.currentValue ?? data.startValue,
98	    unit: data.unit,
99	    deadline: data.deadline || null,
100	    linkedHabitIds: data.linkedHabitIds || [],
101	    isArchived: false,
102	    createdAt: new Date().toISOString(),
103	    updatedAt: new Date().toISOString(),
104	  };
105	  store.goals.push(goal);
106	  return goal;
107	}
