120	export function createGoalLog(data: {
121	  goalId: string;
122	  previousValue: number;
123	  newValue: number;
124	  delta: number;
125	  note?: string | null;
126	}): GoalLog {
127	  const log: GoalLog = {
128	    id: crypto.randomUUID(),
129	    goalId: data.goalId,
130	    userId: "demo",
131	    previousValue: data.previousValue,
132	    newValue: data.newValue,
133	    delta: data.delta,
134	    note: data.note ?? null,
135	    createdAt: new Date().toISOString(),
136	  };
137	  store.goalLogs.push(log);
138	  return log;
139	}
140	
141	export function getGoalLogsByGoalId(goalId: string): GoalLog[] {
142	  return store.goalLogs.filter((l: GoalLog) => l.goalId === goalId);
143	}
