22	      }
23	
24	      const message = `作为个人成长教练，根据以下本周数据给一段简短的洞察（200字以内）：
25	完成情况: ${logs.map((l) => `${l.date}: ${l.completed}/${l.total}`).join(", ")}
26	活跃习惯: ${habits.map((h: any) => h.title).join("、")}
27	指出1-2个趋势，给出1条具体改进建议。语气像帝王侍读。`;
28	
29	      const text = await getAIRecommendation(message);
30	      return NextResponse.json({ text });
31	    }
